 header('Content-Type: application/json'); require_once __DIR__ . '/bootstrap.php'; $config = fmLoadRuntimeConfig(__DIR__); define('AUTH_CALLBACK', $config['AUTH_CALLBACK']); define('ALLOWED_IPS', $config['ALLOWED_IPS']); define('CORS_ENABLED', $config['CORS_ENABLED']); define('CORS_ALLOWED_ORIGINS', $config['CORS_ALLOWED_ORIGINS']); define('RATE_LIMIT_ENABLED', $config['RATE_LIMIT_ENABLED']); define('RATE_LIMIT_MAX_REQUESTS', $config['RATE_LIMIT_MAX_REQUESTS']); define('RATE_LIMIT_WINDOW', $config['RATE_LIMIT_WINDOW']); fmRequireRuntimePhp(__DIR__, '../../security/Auth.php'); $auth = new \FilesManager\Auth(); $auth->requireAuth(); define('BASE_PATH', $config['BASE_PATH']); define('FRONTEND_ROOT_PATH', $config['FRONTEND_ROOT_PATH']); define('MAX_FILE_SIZE', $config['MAX_FILE_SIZE']); define('ALLOWED_EXTENSIONS', $config['ALLOWED_EXTENSIONS']); define('ALLOWED_MIMES', $config['ALLOWED_MIMES']); define('ENABLE_CSRF', $config['ENABLE_CSRF']); define('DEBUG', $config['DEBUG']); define('INDEX_HTML_READ_ONLY', $config['INDEX_HTML_READ_ONLY']); fmRequireRuntimePhp(__DIR__, '../../security/Validator.php'); fmRequireRuntimePhp(__DIR__, '../../shared/backend/Traits/Loggable.php'); fmRequireRuntimePhp(__DIR__, '../../shared/backend/Traits/Validatable.php'); fmRequireRuntimePhp(__DIR__, '../../features/upload/backend/Uploader.php'); use FilesManager\Validator; use FilesManager\Uploader; session_start(); function validateCsrf(): void { if (!ENABLE_CSRF || in_array($_SERVER['REMOTE_ADDR'] ?? '', ['127.0.0.1', '::1'])) { return; } $token = $_POST['csrf_token'] ?? $_SERVER['HTTP_X_CSRF_TOKEN'] ?? ''; if (!isset($_SESSION['csrf_token']) || !Validator::validateCsrfToken($token, $_SESSION['csrf_token'])) { errorResponse('Token CSRF inválido', 403); } } function jsonResponse(mixed $data, int $statusCode = 200): void { http_response_code($statusCode); echo json_encode($data); exit; } function errorResponse(string $message, int $statusCode = 400, array $extra = []): void { jsonResponse(array_merge([ 'success' => false, 'message' => $message, 'error' => $message, ], $extra), $statusCode); } function normalizePath(string $path): string { $path = trim($path); $path = str_replace(['\\', '//'], '/', $path); $path = preg_replace('#/+#', '/', $path); if (empty($path)) { return '/'; } $frontendRoot = rtrim(FRONTEND_ROOT_PATH, '/'); if (!empty($frontendRoot) && strpos($path, $frontendRoot) === 0) { $path = substr($path, strlen($frontendRoot)); } if (empty($path)) { return '/'; } if ($path[0] !== '/') { $path = '/' . $path; } return $path; } function normalizeFilesArray(array $files): array { $normalized = []; if (isset($files['name']) && is_array($files['name'])) { foreach ($files['name'] as $key => $value) { $normalized[] = [ 'name' => $files['name'][$key], 'type' => $files['type'][$key], 'tmp_name' => $files['tmp_name'][$key], 'error' => $files['error'][$key], 'size' => $files['size'][$key], ]; } } else { $normalized[] = $files; } return $normalized; } validateCsrf(); try { if (empty($_FILES['files'])) { throw new \Exception('Nenhum arquivo enviado'); } $files = normalizeFilesArray($_FILES['files']); if (INDEX_HTML_READ_ONLY) { foreach ($files as $file) { $fileName = strtolower(basename($file['name'] ?? '')); if ($fileName === 'index.html') { throw new \Exception('Arquivo index.html é somente leitura'); } } } $targetPath = normalizePath($_POST['targetPath'] ?? '/'); $conflictAction = $_POST['conflictAction'] ?? null; $uploader = new Uploader(BASE_PATH, MAX_FILE_SIZE, ALLOWED_EXTENSIONS, ALLOWED_MIMES); $results = $uploader->uploadMultiple($files, $targetPath, $conflictAction); $success = array_filter($results, fn($r) => $r['success']); $failed = array_filter($results, fn($r) => !$r['success']); jsonResponse([ 'success' => true, 'message' => 'Upload concluído', 'uploaded' => count($success), 'failed' => count($failed), 'results' => $results, ]); } catch (\Exception $e) { errorResponse($e->getMessage(), 400); } 